  function esc(value){
    return String(value == null ? '' : value)
      .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;').replace(/'/g, '&#39;');
  }
  function currentLocale(){
    try{ if(typeof currentLang === 'string' && currentLang) return currentLang; }catch(err){}
    try{ if(window.currentLang) return window.currentLang; }catch(err){}
    try{ return localStorage.getItem('cryptoAcademyLang') || document.documentElement.lang || 'en'; }catch(err){}
    return 'en';
  }
  function copy(){ return COPY[currentLocale()] || COPY.en; }
  function isRtl(){ return currentLocale() === 'ar'; }
  function basePrefix(){ try{ if(typeof getBasePrefix === 'function') return getBasePrefix(); }catch(err){} return ''; }
  function routeToPitch(){ return basePrefix() + '#pitch'; }
  function mailto(){ return 'mailto:' + EMAIL + '?subject=' + encodeURIComponent('Coin ProofPath Sponsorship Inquiry'); }

  function readVisitorTotal(){
    var node = document.getElementById('visitorTotalValue');
    if(node && node.textContent.trim()) return node.textContent.trim();
    try{
      var raw = localStorage.getItem('coinProofPathVisitorTotal') || localStorage.getItem('cryptoAcademyTotalVisitors') || localStorage.getItem('visitorTotal') || '';
      var parsed = parseInt(raw, 10);
      if(isFinite(parsed) && parsed > 0) return parsed.toLocaleString();
    }catch(err){}
    return '698+';
  }

  function renderCards(cards, className){
    return (cards || []).map(function(card, index){
      var parts = String(card || '').split('|');
      if(parts.length > 1){
        return '<article class="' + className + '"><span>' + esc(String(index + 1).padStart(2, '0')) + '</span><h3>' + esc(parts[0]) + '</h3><p>' + esc(parts.slice(1).join('|')) + '</p></article>';
      }
      return '<article class="' + className + '"><span>' + esc(String(index + 1).padStart(2, '0')) + '</span><p>' + esc(card) + '</p></article>';
    }).join('');
  }

  function sectionById(p, id){
    var list = p.sections || [];
    for(var i = 0; i < list.length; i++){
      if(list[i] && list[i].id === id) return list[i];
    }
    return { cards:[] };
  }

  function cardTitle(value){
    return String(value || '').split('|')[0];
  }

  function renderVisualIcon(index){
    var icons = [
      '<path d="M7 11l3 3 7-8"/><path d="M12 3l7 3v5c0 4.6-3 7.1-7 8.8C8 18.1 5 15.6 5 11V6l7-3z"/>',
      '<rect x="4" y="6" width="16" height="12" rx="3"/><path d="M8 10h6"/><path d="M16 14h.01"/>',
      '<path d="M5 16h14"/><path d="M7 12l5-5 5 5"/><path d="M12 7v9"/>',
      '<circle cx="12" cy="12" r="8"/><path d="M9 12l2 2 4-5"/>',
      '<path d="M4 7h16"/><path d="M7 4h10v16H7z"/><path d="M10 10h4"/><path d="M10 14h4"/>'
    ];
    return '<svg viewBox="0 0 24 24" aria-hidden="true" focusable="false">' + icons[index % icons.length] + '</svg>';
  }

  function renderVisualCard(label, index){
    return '<article class="pitch-visual-card"><span class="pitch-visual-icon">' + renderVisualIcon(index) + '</span><strong>' + esc(cardTitle(label)) + '</strong></article>';
  }

  function renderVisualCardList(cards, limit){
    return (cards || []).slice(0, limit || 6).map(renderVisualCard).join('');
  }

  function renderHeroVisual(p){
    var solution = sectionById(p, 'solution');
    return '<div class="pitch-visual pitch-hero-visual" aria-label="' + esc(p.title) + '">'
      + '<div class="pitch-browser">'
      + '<div class="pitch-browser-bar"><span></span><span></span><span></span></div>'
      + '<div class="pitch-browser-body">'
      + '<div class="pitch-browser-main"><strong>' + esc(BRAND) + '</strong><div class="pitch-visual-lines"><span></span><span></span><span></span></div></div>'
      + '<div class="pitch-visual-card-grid compact">' + renderVisualCardList(solution.cards, 4) + '</div>'
      + '</div></div>'
      + '<div class="pitch-orbit"><span></span><span></span><span></span></div>'
      + '</div>';
  }

  function renderProblemVisual(section){
    return '<div class="pitch-visual pitch-flow-visual is-problem" aria-label="' + esc(section.title) + '">'
      + '<div class="pitch-flow-row">' + renderVisualCardList(section.cards, 4) + '</div>'
      + '<div class="pitch-risk-meter"><span></span><span></span><span></span><span></span></div>'
      + '</div>';
  }

  function renderSolutionVisual(section){
    return '<div class="pitch-visual pitch-system-visual" aria-label="' + esc(section.title) + '">'
      + '<div class="pitch-system-core"><strong>' + esc(BRAND) + '</strong></div>'
      + '<div class="pitch-system-ring">' + renderVisualCardList(section.cards, 6) + '</div>'
      + '</div>';
  }

  function renderProductVisual(p, section){
    var roadmaps = sectionById(p, 'roadmaps');
    return '<div class="pitch-visual pitch-product-visual" aria-label="' + esc(section.title) + '">'
      + '<div class="pitch-browser">'
      + '<div class="pitch-browser-bar"><span></span><span></span><span></span></div>'
      + '<div class="pitch-product-body">'
      + '<div class="pitch-product-sidebar"><span></span><span></span><span></span></div>'
      + '<div class="pitch-product-grid">' + renderVisualCardList(roadmaps.cards, 3) + renderVisualCardList(section.cards, 4) + '</div>'
      + '</div></div></div>';
  }

  function renderSponsorFlowVisual(section){
    return '<div class="pitch-visual pitch-flow-visual is-sponsor" aria-label="' + esc(section.title) + '">'
      + '<div class="pitch-flow-row">' + renderVisualCardList(section.cards, 5) + '</div>'
      + '</div>';
  }

  function renderPitchVisual(section, p){
    if(section.id === 'problem') return renderProblemVisual(section);
    if(section.id === 'solution') return renderSolutionVisual(section);
    if(section.id === 'overview') return renderProductVisual(p, section);
    if(section.id === 'value') return renderSponsorFlowVisual(section);
    return '';
  }

  function renderPitchPage(){
    var p = copy();
    var sections = (p.sections || []).map(function(section){
      var className = section.id === 'packages' ? 'pitch-card pitch-package-card' : 'pitch-card';
      return '<section class="pitch-section" id="pitch-' + esc(section.id) + '">'
        + '<div class="pitch-section-head"><div><div class="pitch-kicker">' + esc(section.kicker) + '</div><h2>' + esc(section.title) + '</h2></div><p>' + esc(section.lead) + '</p></div>'
        + renderPitchVisual(section, p)
        + '<div class="pitch-grid ' + (section.id === 'roadmaps' ? 'is-roadmaps' : '') + '">' + renderCards(section.cards, className) + '</div>'
        + '</section>';
    }).join('');
    return '<div class="pitch-page-shell" dir="' + (isRtl() ? 'rtl' : 'ltr') + '">'
      + '<section class="pitch-cover">'
      + '<div class="pitch-kicker">' + esc(p.navSub) + '</div>'
      + '<h1>' + esc(BRAND) + '</h1>'
      + '<p class="pitch-subtitle">' + esc(p.subtitle) + '</p>'
      + '<p class="pitch-description">' + esc(p.description) + '</p>'
      + '<div class="pitch-actions"><a class="pitch-btn is-primary" href="#pitch-packages">' + esc(p.primaryCta) + '</a><a class="pitch-btn" href="' + esc(mailto()) + '">' + esc(p.contactCta) + '</a></div>'
      + renderHeroVisual(p)
      + '</section>'
      + sections
      + '<section class="pitch-section pitch-metrics-live"><div><div class="pitch-kicker">' + esc(p.liveSignal || 'Live signal') + '</div><h2>' + esc(p.visitorCounter || ((currentLocale() === 'ko') ? '방문자 카운터' : 'Visitor counter')) + '</h2></div><strong>' + esc(readVisitorTotal()) + '</strong></section>'
      + '<section class="pitch-contact"><div><div class="pitch-kicker">' + esc(p.footerContact) + '</div><h2>' + esc(p.contactTitle) + '</h2><p>' + esc(p.contactText) + '</p><p class="pitch-legal">' + esc(p.legal) + '</p></div><a class="pitch-btn is-primary" href="' + esc(mailto()) + '">' + esc(p.contactButton) + '</a></section>'
      + '</div>';
  }

