      '.pitch-orbit{position:absolute;right:22px;top:22px;display:grid;gap:9px}.pitch-orbit span{width:12px;height:12px;border-radius:999px;background:#7aa38b;box-shadow:0 0 0 8px rgba(122,163,139,.14)}.pitch-orbit span:nth-child(2){background:#d7b16b}.pitch-orbit span:nth-child(3){background:#2f5f91}',
