      '.pitch-flow-visual.is-problem{background:linear-gradient(135deg,#fff,#fff7f4)}.pitch-flow-visual.is-problem .pitch-visual-icon{background:#fff2ec;color:#b85d4a}.pitch-risk-meter{display:grid;grid-template-columns:1.2fr .9fr .7fr .5fr;gap:6px;margin-top:14px}.pitch-risk-meter span{height:8px;border-radius:999px;background:#f2d9ce}.pitch-risk-meter span:nth-child(2){background:#edc5b7}.pitch-risk-meter span:nth-child(3){background:#dda08f}.pitch-risk-meter span:nth-child(4){background:#b85d4a}',
      '.pitch-system-visual{display:grid;grid-template-columns:minmax(180px,.45fr) minmax(0,1fr);gap:18px;align-items:center}.pitch-system-core{min-height:180px;border-radius:24px;background:linear-gradient(135deg,#18304f,#2f5f91);color:#fff;display:flex;align-items:center;justify-content:center;text-align:center;padding:18px;box-shadow:0 18px 36px rgba(24,48,79,.18)}.pitch-system-core strong{font-size:clamp(1.25rem,2.4vw,2rem);letter-spacing:-.04em}.pitch-system-ring{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:10px}',
