      '@media (max-width:620px){.pitch-cover,.pitch-section,.pitch-contact,.pitch-metrics-live{border-radius:18px;padding:18px}.pitch-grid,.pitch-grid.is-roadmaps{grid-template-columns:1fr}.pitch-home-entry,.pitch-crosslink-card{grid-template-columns:1fr}.pitch-home-entry button,.pitch-crosslink-card button,.pitch-btn{width:100%}.pitch-visual{border-radius:18px;margin:18px 0;padding:14px}.pitch-visual-card-grid,.pitch-flow-row,.pitch-system-ring,.pitch-product-grid{grid-template-columns:1fr}.pitch-browser-main{min-height:150px}.pitch-product-sidebar{display:none}}'
